const CSS = `
@import url('https://fonts.googleapis.com/css2?family=DM+Serif+Display:ital@0;1&family=JetBrains+Mono:wght@300;400;500&display=swap');
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
:root {
  --bg: #05080f; --s1: #0d1117; --s2: #161c27; --border: rgba(255,255,255,0.06);
  --green: #00d97e; --amber: #f0b429; --blue: #4f8ef7; --red: #ff5c5c;
  --text: #dce6f0; --muted: #4a5568;
  --font-display: 'DM Serif Display', serif;
  --font-mono: 'JetBrains Mono', monospace;
}
body { background: var(--bg); color: var(--text); font-family: var(--font-mono); font-size: 14px; line-height: 1.6; }
.app { min-height: 100vh; position: relative; overflow-x: hidden; }
.bg-grid {
  position: fixed; inset: 0;
  background-image: linear-gradient(rgba(79,142,247,0.03) 1px, transparent 1px), linear-gradient(90deg, rgba(79,142,247,0.03) 1px, transparent 1px);
  background-size: 40px 40px; pointer-events: none; z-index: 0;
}
.header {
  position: relative; z-index: 10; text-align: center; padding: 3rem 1.5rem 2rem;
  background: radial-gradient(ellipse 70% 60% at 50% 0%, rgba(79,142,247,0.08) 0%, transparent 70%);
}
.header-eyebrow { font-size: 0.6rem; letter-spacing: 0.35em; color: var(--green); text-transform: uppercase; margin-bottom: 1rem; display: flex; align-items: center; justify-content: center; gap: 0.5rem; }
.dot { width: 6px; height: 6px; background: var(--green); border-radius: 50%; box-shadow: 0 0 8px var(--green); animation: pulse 2s ease infinite; }
@keyframes pulse { 0%,100% { opacity:1; transform:scale(1); } 50% { opacity:.5; transform:scale(.8); } }
.header h1 { font-family: var(--font-display); font-size: clamp(2.8rem, 7vw, 5rem); line-height: 1; color: #fff; margin-bottom: 0.75rem; }
.header h1 em { font-style: italic; background: linear-gradient(135deg, var(--amber) 0%, #ff6b35 100%); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
.header-sub { font-size: 0.68rem; color: var(--muted); letter-spacing: 0.06em; margin-bottom: 1.5rem; }

/* Language toggle */
.lang-toggle { display: flex; gap: 0.4rem; justify-content: center; margin-bottom: 1.25rem; }
.lang-btn { padding: 0.3rem 0.85rem; background: var(--s1); border: 1px solid var(--border); border-radius: 99px; font-family: var(--font-mono); font-size: 0.7rem; color: var(--muted); cursor: pointer; transition: all 0.15s; }
.lang-btn.active { background: rgba(240,180,41,0.12); border-color: rgba(240,180,41,0.35); color: var(--amber); }
.lang-btn:hover { color: var(--text); }

/* Country filter */
.search-wrap { max-width: 640px; margin: 0 auto; position: relative; }
.country-filter-row { display: flex; gap: 0.35rem; flex-wrap: wrap; justify-content: center; margin-bottom: 0.75rem; }
.country-chip { padding: 0.25rem 0.65rem; background: var(--s1); border: 1px solid var(--border); border-radius: 99px; font-family: var(--font-mono); font-size: 0.65rem; color: var(--muted); cursor: pointer; transition: all 0.15s; white-space: nowrap; }
.country-chip.active { background: rgba(79,142,247,0.12); border-color: rgba(79,142,247,0.35); color: var(--blue); }
.country-chip:hover { color: var(--text); border-color: rgba(255,255,255,0.15); }

/* Search */
.search-box { display: flex; align-items: center; background: var(--s1); border: 1px solid var(--border); border-radius: 10px; transition: border-color 0.2s, box-shadow 0.2s; }
.search-box:focus-within { border-color: rgba(79,142,247,0.4); box-shadow: 0 0 0 3px rgba(79,142,247,0.07); }
.search-icon { padding: 0 1rem 0 1.25rem; color: var(--muted); font-size: 1.1rem; }
.search-input { flex: 1; background: transparent; border: none; outline: none; padding: 0.9rem 0; font-family: var(--font-mono); font-size: 0.85rem; color: var(--text); caret-color: var(--amber); }
.search-input::placeholder { color: var(--muted); }
.search-spinner { width: 16px; height: 16px; border: 2px solid var(--border); border-top-color: var(--amber); border-radius: 50%; animation: spin 0.7s linear infinite; margin-right: 1rem; flex-shrink: 0; }
@keyframes spin { to { transform: rotate(360deg); } }
.suggestions { position: absolute; top: calc(100% + 6px); left: 0; right: 0; background: var(--s1); border: 1px solid var(--border); border-radius: 10px; z-index: 200; overflow: hidden; box-shadow: 0 24px 60px rgba(0,0,0,0.6); }
.suggestion-item { width: 100%; display: flex; align-items: center; gap: 0.85rem; padding: 0.75rem 1.1rem; background: none; border: none; border-bottom: 1px solid var(--border); cursor: pointer; transition: background 0.15s; text-align: left; }
.suggestion-item:last-child { border-bottom: none; }
.suggestion-item:hover { background: var(--s2); }
.sug-flag { font-size: 1.4rem; flex-shrink: 0; }
.sug-info { flex: 1; min-width: 0; }
.sug-name { display: block; font-size: 0.82rem; color: var(--text); font-weight: 500; }
.sug-meta { display: block; font-size: 0.65rem; color: var(--muted); margin-top: 0.1rem; }
.sug-party { padding: 0.15rem 0.5rem; background: rgba(240,180,41,0.1); border: 1px solid rgba(240,180,41,0.2); border-radius: 4px; font-size: 0.62rem; color: var(--amber); flex-shrink: 0; }

/* Trending */
.trending { position: relative; z-index: 5; text-align: center; padding: 0 1.5rem 3rem; }
.trending-label { font-size: 0.65rem; letter-spacing: 0.15em; color: var(--muted); text-transform: uppercase; margin-bottom: 1rem; }
.trending-list { display: flex; gap: 0.5rem; flex-wrap: wrap; justify-content: center; }
.trending-chip { padding: 0.35rem 0.85rem; background: var(--s1); border: 1px solid var(--border); border-radius: 99px; font-family: var(--font-mono); font-size: 0.72rem; color: var(--text); cursor: pointer; transition: all 0.15s; display: flex; align-items: center; gap: 0.4rem; }
.trending-chip span { color: var(--muted); font-size: 0.62rem; }
.trending-chip:hover { border-color: rgba(79,142,247,0.35); color: var(--blue); }

/* Main */
.main { position: relative; z-index: 5; max-width: 820px; margin: 0 auto; padding: 0 1.5rem 3rem; animation: fadeUp 0.35s ease; }
@keyframes fadeUp { from { opacity: 0; transform: translateY(14px); } to { opacity: 1; transform: translateY(0); } }

/* Politician header */
.pol-header { display: flex; align-items: center; gap: 1.25rem; background: var(--s1); border: 1px solid var(--border); border-radius: 14px; padding: 1.5rem; margin-bottom: 1.25rem; }
.pol-avatar { width: 56px; height: 56px; background: var(--s2); border: 1px solid var(--border); border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 1.8rem; flex-shrink: 0; }
.pol-info { flex: 1; }
.pol-info h2 { font-family: var(--font-display); font-size: 1.4rem; color: #fff; margin-bottom: 0.4rem; }
.pol-badges { display: flex; gap: 0.4rem; flex-wrap: wrap; }
.pol-lang-hint { flex-shrink: 0; }
.lang-indicator { font-size: 0.7rem; color: var(--muted); }
.badge { padding: 0.18rem 0.55rem; border-radius: 4px; font-size: 0.62rem; letter-spacing: 0.06em; font-weight: 500; }
.badge-party  { background: rgba(240,180,41,0.1); border: 1px solid rgba(240,180,41,0.22); color: var(--amber); }
.badge-state  { background: rgba(79,142,247,0.1); border: 1px solid rgba(79,142,247,0.22); color: var(--blue); }
.badge-country{ background: rgba(0,217,126,0.08); border: 1px solid rgba(0,217,126,0.2); color: var(--green); }
.badge-role   { background: rgba(255,255,255,0.04); border: 1px solid var(--border); color: var(--muted); }

/* Tabs */
.tabs { display: flex; gap: 0.4rem; margin-bottom: 1.25rem; overflow-x: auto; scrollbar-width: none; padding-bottom: 2px; }
.tabs::-webkit-scrollbar { display: none; }
.tab { display: flex; align-items: center; gap: 0.35rem; padding: 0.5rem 1rem; background: var(--s1); border: 1px solid var(--border); border-radius: 8px; font-family: var(--font-mono); font-size: 0.72rem; color: var(--muted); cursor: pointer; white-space: nowrap; transition: all 0.15s; }
.tab:hover { border-color: rgba(255,255,255,0.12); color: var(--text); }
.tab.active { background: rgba(79,142,247,0.1); border-color: rgba(79,142,247,0.35); color: var(--blue); }
.tab-dot { width: 5px; height: 5px; background: var(--green); border-radius: 50%; box-shadow: 0 0 6px var(--green); }

/* Panel */
.panel { background: var(--s1); border: 1px solid var(--border); border-radius: 14px; overflow: hidden; }
.panel-head { display: flex; align-items: center; justify-content: space-between; padding: 1rem 1.5rem; border-bottom: 1px solid var(--border); background: var(--s2); }
.panel-title { font-size: 0.8rem; font-weight: 500; display: flex; align-items: center; gap: 0.5rem; }
.cache-tag { padding: 0.1rem 0.4rem; background: rgba(0,217,126,0.1); border: 1px solid rgba(0,217,126,0.2); border-radius: 3px; font-size: 0.55rem; color: var(--green); letter-spacing: 0.08em; }
.panel-model { font-size: 0.62rem; color: var(--muted); }
.panel-body { padding: 1.5rem; min-height: 260px; }
.ai-text { font-size: 0.82rem; line-height: 1.9; color: #b8c9d9; white-space: pre-wrap; }

/* Legal records */
.legal-records { margin-top: 1.5rem; padding-top: 1.5rem; border-top: 1px solid var(--border); }
.legal-records-title { font-size: 0.68rem; letter-spacing: 0.1em; color: var(--muted); text-transform: uppercase; margin-bottom: 0.85rem; }
.legal-item { padding: 0.85rem 1rem; border-radius: 8px; margin-bottom: 0.5rem; border: 1px solid var(--border); background: rgba(255,255,255,0.02); }
.legal-item--condenado,.legal-item--inelegibilidade { border-color: rgba(255,92,92,0.2); background: rgba(255,92,92,0.04); }
.legal-item--verificar { border-color: rgba(240,180,41,0.15); background: rgba(240,180,41,0.03); }
.legal-item--arquivado,.legal-item--absolvido { border-color: rgba(0,217,126,0.15); background: rgba(0,217,126,0.03); }
.legal-item-head { display: flex; align-items: center; gap: 0.5rem; flex-wrap: wrap; margin-bottom: 0.4rem; }
.legal-badge { padding: 0.15rem 0.5rem; border-radius: 4px; font-size: 0.58rem; font-weight: 600; letter-spacing: 0.08em; }
.legal-badge--inelegibilidade,.legal-badge--condenacao,.legal-badge--acao_penal { background: rgba(255,92,92,0.15); border: 1px solid rgba(255,92,92,0.3); color: var(--red); }
.legal-badge--multa_tcu { background: rgba(240,180,41,0.15); border: 1px solid rgba(240,180,41,0.3); color: var(--amber); }
.legal-badge--consulta_stf,.legal-badge--consulta_tcu { background: rgba(79,142,247,0.1); border: 1px solid rgba(79,142,247,0.25); color: var(--blue); }
.legal-court { font-size: 0.65rem; color: var(--muted); font-weight: 500; }
.legal-year { font-size: 0.62rem; color: var(--muted); margin-left: auto; }
.legal-proc { font-size: 0.6rem; color: var(--muted); font-family: var(--font-mono); }
.legal-subject { font-size: 0.75rem; color: #b8c9d9; line-height: 1.6; margin-bottom: 0.35rem; }
.legal-link { font-size: 0.62rem; color: var(--blue); text-decoration: none; letter-spacing: 0.04em; }
.legal-link:hover { text-decoration: underline; }

/* External links */
.external-links { margin-top: 1.25rem; padding-top: 1.25rem; border-top: 1px solid var(--border); }
.external-links-title { font-size: 0.68rem; letter-spacing: 0.1em; color: var(--muted); text-transform: uppercase; margin-bottom: 0.75rem; }
.external-links-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(210px, 1fr)); gap: 0.5rem; }
.ext-link-card { display: flex; flex-direction: column; gap: 0.2rem; padding: 0.75rem 0.9rem; background: var(--s2); border: 1px solid var(--border); border-radius: 8px; text-decoration: none; transition: border-color 0.15s, background 0.15s; position: relative; }
.ext-link-card:hover { border-color: rgba(79,142,247,0.3); background: rgba(79,142,247,0.05); }
.ext-link-label { font-size: 0.72rem; color: var(--text); font-weight: 500; padding-right: 1rem; }
.ext-link-desc { font-size: 0.62rem; color: var(--muted); line-height: 1.4; }
.ext-link-arrow { position: absolute; top: 0.65rem; right: 0.75rem; font-size: 0.7rem; color: var(--blue); }

/* Public data */
.public-data { margin-top: 1.5rem; padding-top: 1.5rem; border-top: 1px solid var(--border); }
.public-data-title { font-size: 0.68rem; letter-spacing: 0.1em; color: var(--muted); text-transform: uppercase; margin-bottom: 0.75rem; }
.public-data-item { display: flex; align-items: center; gap: 0.75rem; padding: 0.5rem 0; border-bottom: 1px solid var(--border); font-size: 0.72rem; }
.public-data-item:last-child { border-bottom: none; }
.pd-source { padding: 0.1rem 0.4rem; background: rgba(79,142,247,0.1); border: 1px solid rgba(79,142,247,0.2); border-radius: 3px; font-size: 0.6rem; color: var(--blue); flex-shrink: 0; }
.pd-title { flex: 1; color: var(--text); }
.pd-date { color: var(--muted); flex-shrink: 0; }

/* Panel footer */
.panel-footer { display: flex; align-items: center; gap: 0.5rem; flex-wrap: wrap; padding: 0.85rem 1.5rem; border-top: 1px solid var(--border); background: var(--s2); font-size: 0.62rem; color: var(--muted); }
.source-chip { padding: 0.1rem 0.45rem; background: rgba(255,255,255,0.03); border: 1px solid var(--border); border-radius: 3px; color: var(--muted); }
.meta-tokens { margin-left: auto; color: var(--muted); font-size: 0.58rem; }

/* States */
.state-loading { display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 1.25rem; padding: 3rem; }
.spinner { width: 36px; height: 36px; border: 2px solid var(--border); border-top-color: var(--amber); border-radius: 50%; animation: spin 0.7s linear infinite; }
.loading-text { font-size: 0.7rem; color: var(--muted); letter-spacing: 0.1em; animation: blink 1.5s ease infinite; }
@keyframes blink { 0%,100%{opacity:.4} 50%{opacity:1} }
.state-error { display: flex; align-items: center; gap: 1rem; padding: 2rem; color: var(--red); font-size: 0.8rem; }
.error-icon { font-size: 1.5rem; }
.state-empty { display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 0.75rem; padding: 3rem; text-align: center; }
.empty-icon { font-size: 2.5rem; opacity: 0.2; }
.state-empty p { font-size: 0.75rem; color: var(--muted); }

/* Empty hero */
.empty-hero { position: relative; z-index: 5; text-align: center; padding: 4rem 1.5rem; }
.empty-hero-icon { font-size: 3rem; margin-bottom: 1rem; opacity: 0.3; }
.empty-hero h3 { font-family: var(--font-display); font-size: 1.6rem; color: var(--muted); margin-bottom: 0.75rem; }
.empty-hero p { font-size: 0.75rem; color: var(--muted); opacity: 0.6; line-height: 1.8; white-space: pre-line; }

/* Footer */
.footer { text-align: center; padding: 2rem; font-size: 0.62rem; color: var(--muted); opacity: 0.5; position: relative; z-index: 5; }

/* Cursor */
.cursor { display: inline-block; width: 7px; height: 13px; background: var(--amber); margin-left: 2px; vertical-align: middle; animation: blink2 1s step-end infinite; border-radius: 1px; }
@keyframes blink2 { 0%,100%{opacity:1} 50%{opacity:0} }

@media (max-width: 600px) {
  .pol-header { flex-direction: column; text-align: center; }
  .pol-badges { justify-content: center; }
  .pol-lang-hint { display: none; }
}
